const usd = n => new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD', maximumFractionDigits: 0 }).format(n);
const now = new Date();
const weekAgo = new Date(now.getTime() - 7*24*60*60*1000).toISOString().slice(0,10);
const rows = $input.all().map(i => i.json.fields);
const windowed = rows.filter(r => r['Date Introduced'] >= weekAgo);
const ordersThisWeek = rows.filter(r => r.Status === 'order_placed' && (r['Date First Order'] || '') >= weekAgo);
const revenueThisWeek = ordersThisWeek.reduce((s, r) => s + Number(r['First Order Amount'] || 0), 0);
const payoutThisWeek = revenueThisWeek * 0.15;
const byCampaign = {};
for (const r of windowed) {
  const k = r.Campaign || 'Uncategorized';
  byCampaign[k] = (byCampaign[k] || 0) + 1;
}
const topCampaigns = Object.entries(byCampaign)
  .sort((a,b) => b[1]-a[1])
  .slice(0,5)
  .map(([k,v]) => `• ${k}: *${v}*`)
  .join('\n');
const conv = windowed.length ? Math.round((ordersThisWeek.length / windowed.length) * 100) : 0;
return [{ json: {
  newHandoffs:      windowed.length,
  newOrders:        ordersThisWeek.length,
  conversionPct:    conv,
  revenueFmt:       usd(revenueThisWeek),
  payoutFmt:        usd(payoutThisWeek),
  topCampaigns,
  weekStart:        weekAgo
}}];
